resource "aws_ebs_volume" "data" {
  availability_zone = "us-east-1a"
  size              = 100       # GB
  type              = "gp3"
  iops              = 3000      # gp3 baseline; can set up to 16,000
  throughput        = 125       # MB/s
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs.arn
  tags = { Name = "db-data" }
}

resource "aws_volume_attachment" "data" {
  device_name = "/dev/sdf"
  volume_id   = aws_ebs_volume.data.id
  instance_id = aws_instance.db.id
}

resource "aws_backup_plan" "daily" {
  name = "daily-backup-plan"
  rule {
    rule_name         = "daily-7-day-retention"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 2 * * ? *)"  # 02:00 UTC daily
    lifecycle {
      delete_after = 7   # days
    }
  }
}

# Apply plan to all resources tagged backup=true
resource "aws_backup_selection" "tagged" {
  plan_id      = aws_backup_plan.daily.id
  name         = "tagged-resources"
  iam_role_arn = aws_iam_role.backup.arn
  selection_tag {
    type  = "STRINGEQUALS"
    key   = "backup"
    value = "true"
  }
}

resource "aws_dlm_lifecycle_policy" "ebs_daily" {
  description        = "Daily EBS snapshot — 7 day retention"
  execution_role_arn = aws_iam_role.dlm.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]
    schedule {
      name = "Daily snapshots"
      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["02:00"]
      }
      retain_rule {
        count = 7
      }
      copy_tags = true
    }
    target_tags = {
      snapshot = "true"
    }
  }
}
